	const keys = new Set<string>();
	const trimmed = output.trim();
	if (!trimmed) {
		return keys;
	}
	try {
		const parsed = JSON.parse(trimmed);
		const list = Array.isArray(parsed)
			? parsed
			: Array.isArray((parsed as { envs?: unknown }).envs)
				? ((parsed as { envs: unknown[] }).envs as unknown[])
				: [];
